// Anonymous Wealth Proof -- Noir Circuit
//
// Proves: "I (the holder of a specific Ethereum address) hold >= threshold Wei"
// Without revealing: the address itself, the exact balance
//
// Architecture:
//   1. Prover calls eth_getProof for their address at a known block
//   2. This circuit verifies the MPT state proof against state_root
//   3. Extracts balance from the RLP-encoded account state
//   4. Asserts balance >= threshold
//   5. Computes EIP-191 msg_hash = keccak256("\x19Ethereum Signed Message:\n32" || state_root)
//      INSIDE the circuit, so verifiers don't need to check this externally
//   6. Verifies an ECDSA signature over the computed msg_hash to prove key ownership
//   7. Returns a Pedersen commitment binding (address, balance) to the proof

use ::trie::{
    trie_proof::TrieProof,
    const::MAX_ACCOUNT_STATE_LENGTH,
    rlp,
    utils::byte_value,
};
use keccak::keccak256;

// Circuit size constants

// Depth-10 state proof: 10 Ethereum MPT nodes x 532 bytes per node = 5320 bytes
// This covers any address in mainnet Ethereum (max trie depth observed ~= 9-10).
// For shallower tries, unused tail bytes remain zero and `depth` controls iteration.
global DEPTH10_MAX: u32 = 5320;

// Main circuit entry point

/// Anonymous Wealth Proof circuit.
///
/// # Public inputs (visible on-chain / to any verifier)
/// * `state_root`   -- Ethereum block state root (32 bytes). Ties the proof to a
///                     specific block. The verifier should confirm this matches a
///                     canonical chain head.
/// * `threshold`    -- Minimum balance claimed, in Wei (u128 -> max ~3.4e38 Wei,
///                     effectively unlimited for any real-world balance).
/// * `user_tag`     -- 32-byte user-chosen label (keccak of any text, e.g.
///                     keccak("@username")). Binds the proof to an identity so a
///                     reposted proof is clearly labeled. Included in the EIP-712
///                     signed message, so the prover explicitly authorised this tag.
/// * `block_number` -- Ethereum block number at proof generation time. Prevents
///                     replaying old proofs from blocks when the balance was higher.
///                     Signed via EIP-712 so it cannot be changed post-signing.
/// * `chain_id`     -- EVM chain ID (1 = Ethereum mainnet). Prevents cross-chain
///                     replay: a testnet proof cannot be presented as mainnet.
///
/// # Private inputs (known only to the prover, never revealed)
/// * `address`     -- Ethereum address (20 bytes).
/// * `pub_key_x`   -- Signer public key X coordinate (32 bytes, secp256k1).
/// * `pub_key_y`   -- Signer public key Y coordinate (32 bytes, secp256k1).
/// * `signature`   -- ECDSA signature r || s (64 bytes, no recovery id).
/// * `state_proof` -- MPT inclusion proof obtained via `eth_getProof`.
///
/// # Return value (also public)
/// * commitment    -- Pedersen([address_as_field, balance_as_field]).
fn main(
    // Public inputs
    state_root:   pub [u8; 32],
    threshold:    pub u128,
    user_tag:     pub [u8; 32],
    block_number: pub u64,
    chain_id:     pub u64,

    // Private inputs
    address:     [u8; 20],
    pub_key_x:   [u8; 32],
    pub_key_y:   [u8; 32],
    signature:   [u8; 64],
    state_proof: TrieProof<20, DEPTH10_MAX, MAX_ACCOUNT_STATE_LENGTH>,
) -> pub Field /* commitment */ {

    // STEP 1 -- Verify the Ethereum Merkle-Patricia Trie state proof.
    //
    // After this assertion, `state_proof.value` is cryptographically bound to
    // the RLP-encoded account state for address `state_proof.key` at `state_root`.
    assert(state_proof.verify_state_root(state_root));

    // STEP 2 -- Bind the private address to the proof key.
    //
    // Prevents the prover from mismatching the private `address` with the key
    // used in the proof (which is hashed to form the MPT path).
    for i in 0..20 {
        assert(state_proof.key[i] == address[i]);
    }

    // STEP 3 -- RLP-decode the Ethereum account state.
    //
    // Ethereum account state layout (EIP-161):
    //   RLP([nonce, balance, storageRoot, codeHash])
    //   index:  0       1        2            3
    //
    // `state_proof.value` is left-padded with zeros (RLP starts after leading zeros).
    // Trie leaf verification uses that layout; `rlp::decode1` expects the list
    // header at index 0, so normalize with `byte_value` first (same as leaf checks).
    let (account_buf, _) = byte_value(state_proof.value);

    // `rlp::decode1` returns an RLP_List where, for string fields, `offset`
    // points directly to the payload bytes (past the RLP length prefix).
    let account_fields: rlp::RLP_List<4> = rlp::decode1(account_buf);

    // STEP 4 -- Extract the balance field (index 1) as a Field element.
    //
    // balance is a big-endian integer of up to 32 bytes (256 bits).
    // ETH total supply ~= 1.2x10^26 Wei < 2^87, so it always fits in u128/Field.
    // Zero balance is encoded as an empty RLP string (length = 0) -> Field(0).
    let balance_field = decode_be_field(
        account_buf,
        account_fields.offset[1],
        account_fields.length[1],
    );

    // STEP 5 -- Assert balance >= threshold (both in Wei).
    //
    // Technique: diff = balance_field - threshold_field.
    //   - If balance >= threshold: diff in [0, 2^87] -> fits in u128 -> cast OK.
    //   - If balance < threshold: diff wraps around BN254 prime (~2^254),
    //     which is >> 2^128 -> the `as u128` range-check constraint fails.
    //
    // This is safe because BN254_PRIME ~2^254 >> 2^128, so there is no false
    // positive: a negative diff is always > 2^128 after modular reduction.
    let diff: Field = balance_field - (threshold as Field);
    // The cast below adds a Noir range constraint: diff must be in [0, 2^128).
    // Proof generation fails here if balance < threshold.
    let _: u128 = diff as u128;

    // STEP 6 -- Prove ownership of `address` via EIP-712 ECDSA signature.
    //
    // Using EIP-712 typed data (instead of raw personal_sign) so MetaMask shows
    // a human-readable prompt rather than garbled binary.
    //
    // The signature simultaneously binds:
    //   - App domain "WealthProof v1"  -- prevents cross-app signature replay
    //   - threshold                    -- a sig for N ETH cannot prove N+1 ETH
    //   - state_root                   -- ties the proof to one specific block
    //   - user_tag                     -- labels proof with user-chosen identity
    //
    // EIP-712 signed hash (computed in-circuit):
    //   msg_hash = keccak256("\x19\x01" || DOMAIN_SEPARATOR || struct_hash)
    //   struct_hash = keccak256(STRUCT_TYPE_HASH
    //                           || abi_uint128(threshold)
    //                           || state_root
    //                           || user_tag)
    //
    // Precomputed constants:
    //   DOMAIN_SEPARATOR: keccak256(abi_encode(
    //     keccak256("EIP712Domain(string name,string version)"),
    //     keccak256("WealthProof"), keccak256("1")))
    //   STRUCT_TYPE_HASH: keccak256(
    //     "WealthClaim(uint128 threshold,bytes32 stateRoot,string userTag,uint64 blockNumber,uint64 chainId)")
    //     Note: EIP-712 encodes `string` as keccak256(utf8_bytes), so `user_tag`
    //     in the circuit is keccak256 of the label the user typed.
    let domain_separator: [u8; 32] = [
        0x16, 0x02, 0x2a, 0x0a, 0x9e, 0xc1, 0xe3, 0xe6,
        0xab, 0xd4, 0x9e, 0xa5, 0xb2, 0x93, 0x63, 0xbe,
        0x21, 0x5d, 0xf8, 0x4f, 0x13, 0x0c, 0x55, 0x74,
        0x56, 0xe0, 0x37, 0xac, 0xc7, 0xb1, 0x58, 0x35,
    ];
    // keccak256("WealthClaim(uint128 threshold,bytes32 stateRoot,string userTag,uint64 blockNumber,uint64 chainId)")
    let struct_type_hash: [u8; 32] = [
        0xa9, 0xe7, 0xd8, 0xdd, 0x71, 0x6c, 0x93, 0xdc,
        0xcb, 0xd7, 0x17, 0x94, 0x19, 0x29, 0x5f, 0x25,
        0xf8, 0x59, 0x21, 0xc4, 0xa6, 0xfd, 0xc4, 0x5f,
        0x59, 0x9c, 0x05, 0x17, 0x0b, 0xbd, 0x41, 0x3d,
    ];

    // struct_hash = keccak256(
    //   struct_type_hash             -- 32 bytes
    //   || abi_uint128(threshold)    -- 32 bytes: 16 zero pad + 16 be
    //   || state_root                -- 32 bytes
    //   || user_tag                  -- 32 bytes (keccak of label string)
    //   || abi_uint64(block_number)  -- 32 bytes: 24 zero pad + 8 be
    //   || abi_uint64(chain_id)      -- 32 bytes: 24 zero pad + 8 be
    // )
    let mut struct_input = [0 as u8; 192];
    for i in 0..32 { struct_input[i] = struct_type_hash[i]; }
    let threshold_bytes = u128_to_be_bytes(threshold);
    // struct_input[32..47] stay 0 (high 16-byte pad for ABI uint128 -> uint256)
    for i in 0..16 { struct_input[48 + i] = threshold_bytes[i]; }
    for i in 0..32 { struct_input[64 + i] = state_root[i]; }
    for i in 0..32 { struct_input[96 + i] = user_tag[i]; }
    let block_number_bytes = u64_to_be_bytes(block_number);
    // struct_input[128..151] stay 0 (high 24-byte pad for ABI uint64 -> uint256)
    for i in 0..8 { struct_input[152 + i] = block_number_bytes[i]; }
    let chain_id_bytes = u64_to_be_bytes(chain_id);
    // struct_input[160..183] stay 0 (high 24-byte pad for ABI uint64 -> uint256)
    for i in 0..8 { struct_input[184 + i] = chain_id_bytes[i]; }
    let struct_hash: [u8; 32] = keccak256(struct_input, 192);

    // msg_hash = keccak256("\x19\x01" || domain_separator || struct_hash)
    let mut final_input = [0 as u8; 66];
    final_input[0] = 0x19;
    final_input[1] = 0x01;
    for i in 0..32 { final_input[2 + i] = domain_separator[i]; }
    for i in 0..32 { final_input[34 + i] = struct_hash[i]; }
    let msg_hash: [u8; 32] = keccak256(final_input, 66);

    assert(std::ecdsa_secp256k1::verify_signature(pub_key_x, pub_key_y, signature, msg_hash));

    // Derive Ethereum address from uncompressed public key and check it matches.
    let mut pubkey_bytes = [0 as u8; 64];
    for i in 0..32 { pubkey_bytes[i] = pub_key_x[i]; }
    for i in 0..32 { pubkey_bytes[32 + i] = pub_key_y[i]; }
    let pubkey_hash: [u8; 32] = keccak256(pubkey_bytes, 64);
    for i in 0..20 {
        assert(pubkey_hash[12 + i] == address[i], "Public key does not match address");
    }

    // STEP 7 -- Compute the privacy-preserving commitment and return it.
    //
    // commitment = Pedersen([pack(address), balance_field])
    //
    // Properties:
    //   - Hiding: infeasible to recover address or balance from commitment alone.
    //   - Binding: commitment uniquely determines (address, balance) under the
    //     discrete-log assumption.
    let address_field = pack_bytes20(address);
    std::hash::pedersen_hash([address_field, balance_field])
}

// Helper functions

/// Interpret `arr[offset .. offset + length]` as a big-endian unsigned integer
/// and return it as a Field element.
///
/// Panics if `length > 32`: the Ethereum balance field is at most 32 bytes (256 bits).
/// Without this guard a malformed witness with `length > 32` would silently truncate,
/// reading only the first 32 bytes and potentially misrepresenting the balance.
fn decode_be_field(
    arr:    [u8; MAX_ACCOUNT_STATE_LENGTH],
    offset: u64,
    length: u64,
) -> Field {
    assert(length <= 32, "balance field too large: max 32 bytes");
    let mut result: Field = 0;
    for i in 0..32_u32 {
        if (i as u64) < length {
            let idx: u32 = (offset + i as u64) as u32;
            result = result * 256 + arr[idx] as Field;
        }
    }
    result
}

/// Pack a 20-byte Ethereum address into a single Field element (big-endian).
/// 20 bytes = 160 bits, well within the BN254 scalar field (~254 bits).
fn pack_bytes20(addr: [u8; 20]) -> Field {
    let mut f: Field = 0;
    for i in 0..20 {
        f = f * 256 + addr[i] as Field;
    }
    f
}

/// Encode a u128 as a 16-byte big-endian array.
fn u128_to_be_bytes(x: u128) -> [u8; 16] {
    let mut bytes = [0 as u8; 16];
    let mut val = x;
    for i in 0..16 {
        bytes[15 - i] = (val & 0xff) as u8;
        val = val >> 8;
    }
    bytes
}

/// Encode a u64 as an 8-byte big-endian array.
fn u64_to_be_bytes(x: u64) -> [u8; 8] {
    let mut bytes = [0 as u8; 8];
    let mut val = x;
    for i in 0..8 {
        bytes[7 - i] = (val & 0xff) as u8;
        val = val >> 8;
    }
    bytes
}

